51	    /**
52	     * Object-level authorization: the caller must be the assigned technician
53	     * or hold ADMIN:WRITE. Prevents cross-user mutation of work orders.
54	     */
55	    private void assertWorkOrderWriteAccess(WorkOrder wo, UUID actorId) {
56	        boolean isAssigned = actorId.equals(wo.getTechnicianUserId());
57	        if (!isAssigned && !SecurityUtils.hasPermission("ADMIN", "WRITE")) {
58	            throw new AppException("FORBIDDEN",
59	                    "You do not have write access to this work order", HttpStatus.FORBIDDEN);
60	        }
61	    }
62	
63	    @Transactional
64	    public WorkOrderResponse createWorkOrder(WorkOrderCreateRequest request, UUID actorId) {
65	        permissionEnforcer.require("WORK_ORDER", "WRITE");
66	        String woNumber = "WO-" + System.currentTimeMillis() + "-" + woSeq.incrementAndGet();
67	        OffsetDateTime now = OffsetDateTime.now();
68	
69	        WorkOrder workOrder = WorkOrder.builder()
70	                .workOrderNumber(woNumber)
71	                .orderId(request.getOrderId())
72	                .status(WorkOrderStatus.SUBMITTED)
73	                .description(request.getDescription())
74	                .slaFirstResponseDueAt(slaService.computeFirstResponseDue(now))
75	                .slaResolutionDueAt(slaService.computeResolutionDue(now))
76	                .build();
77	
78	        workOrder = workOrderRepository.save(workOrder);
79	
80	        // E) Persist attachments supplied at creation time
81	        if (request.getAttachments() != null) {
82	            for (var attachmentDto : request.getAttachments()) {
83	                Attachment attachment = Attachment.builder()
84	                        .ownerType("WORK_ORDER")
85	                        .ownerId(workOrder.getId())
86	                        .blobRef(attachmentDto.getBlobRef())
87	                        .contentType(attachmentDto.getContentType())
88	                        .build();
89	                attachmentRepository.save(attachment);
90	            }
91	        }
92	
93	        auditService.record(actorId, "WORK_ORDER", workOrder.getId().toString(),
94	                "CREATE", "USER_ACTION", null, woNumber);
95	
96	        return toResponse(workOrder);
97	    }
