99	    public WorkOrderResponse getWorkOrder(UUID workOrderId) {
100	        permissionEnforcer.require("WORK_ORDER", "READ");
101	        WorkOrder wo = workOrderRepository.findById(workOrderId)
102	                .orElseThrow(() -> new AppException("WORK_ORDER_NOT_FOUND", "Work order not found", HttpStatus.NOT_FOUND));
103	        return toResponse(wo);
104	    }
