106	    @Transactional
107	    public WorkOrderResponse claimWorkOrder(UUID workOrderId, UUID technicianId) {
108	        permissionEnforcer.require("WORK_ORDER", "WRITE");
109	        WorkOrder wo = workOrderRepository.findByIdWithLock(workOrderId)
110	                .orElseThrow(() -> new AppException("WORK_ORDER_NOT_FOUND", "Work order not found", HttpStatus.NOT_FOUND));
111	
112	        if (wo.getTechnicianUserId() != null) {
113	            throw new AppException("WORK_ORDER_ALREADY_CLAIMED",
114	                    "Work order is already claimed by another technician", HttpStatus.CONFLICT);
115	        }
116	        if (wo.getStatus() != WorkOrderStatus.SUBMITTED) {
117	            throw new AppException("INVALID_STATE", "Work order is not in SUBMITTED status", HttpStatus.CONFLICT);
118	        }
119	
120	        wo.setTechnicianUserId(technicianId);
121	        wo.setStatus(WorkOrderStatus.ASSIGNED);
122	        workOrderRepository.save(wo);
123	
124	        addEventInternal(wo.getId(), WorkOrderEventType.TECHNICIAN_ASSIGNED,
125	                "Claimed by technician " + technicianId, technicianId);
126	
127	        auditService.record(technicianId, "WORK_ORDER", workOrderId.toString(),
128	                "CLAIM_WORK_ORDER", "USER_ACTION",
129	                Map.of("status", WorkOrderStatus.SUBMITTED.name()),
130	                Map.of("status", WorkOrderStatus.ASSIGNED.name(), "technicianId", technicianId.toString()));
131	
132	        return toResponse(wo);
133	    }
134	
135	    @Transactional
136	    public WorkOrderResponse addEvent(UUID workOrderId, WorkOrderEventType type, String payload, UUID actorId) {
137	        permissionEnforcer.require("WORK_ORDER", "WRITE");
138	        WorkOrder wo = workOrderRepository.findById(workOrderId)
139	                .orElseThrow(() -> new AppException("WORK_ORDER_NOT_FOUND", "Work order not found", HttpStatus.NOT_FOUND));
140	        assertWorkOrderWriteAccess(wo, actorId);
141	
142	        addEventInternal(workOrderId, type, payload, actorId);
143	
144	        if (type == WorkOrderEventType.FIRST_RESPONSE_SENT && wo.getFirstRespondedAt() == null) {
145	            wo.setFirstRespondedAt(OffsetDateTime.now());
146	        }
147	        if (type == WorkOrderEventType.RESOLUTION_CONFIRMED) {
148	            wo.setResolvedAt(OffsetDateTime.now());
149	            wo.setStatus(WorkOrderStatus.RESOLVED);
150	            // Q12: auto-lock cost on resolution so it can no longer be edited
151	            workOrderCostRepository.findByWorkOrderId(workOrderId).ifPresent(cost -> {
152	                if (cost.getLockedAt() == null) {
153	                    cost.setLockedAt(OffsetDateTime.now());
154	                    cost.setApprovedStatus("APPROVED");
155	                    workOrderCostRepository.save(cost);
156	                }
157	            });
158	        }
159	        if (type == WorkOrderEventType.STATUS_UPDATED) {
160	            // Keep current status unless specified
161	            wo.setStatus(WorkOrderStatus.IN_PROGRESS);
162	        }
163	        workOrderRepository.save(wo);
164	
165	        return toResponse(wo);
166	    }
167	
168	    private void addEventInternal(UUID workOrderId, WorkOrderEventType type, String payload, UUID actorId) {
169	        WorkOrderEvent event = WorkOrderEvent.builder()
170	                .workOrderId(workOrderId)
171	                .eventType(type)
172	                .payload(payload)
173	                .actorUserId(actorId)
174	                .build();
175	        workOrderEventRepository.save(event);
176	    }
