178	    @Transactional
179	    public WorkOrderResponse updateCost(UUID workOrderId, WorkOrderCostRequest request, UUID actorId) {
180	        permissionEnforcer.require("WORK_ORDER", "WRITE");
181	        WorkOrder wo = workOrderRepository.findById(workOrderId)
182	                .orElseThrow(() -> new AppException("WORK_ORDER_NOT_FOUND", "Work order not found", HttpStatus.NOT_FOUND));
183	        assertWorkOrderWriteAccess(wo, actorId);
184	
185	        // Q12: cost is editable only while the work order is in early states
186	        if (wo.getStatus() == WorkOrderStatus.RESOLVED || wo.getStatus() == WorkOrderStatus.CLOSED) {
187	            throw new AppException("COST_LOCKED",
188	                    "Work order cost cannot be modified in status: " + wo.getStatus(),
189	                    HttpStatus.CONFLICT);
190	        }
191	
192	        WorkOrderCost cost = workOrderCostRepository.findByWorkOrderId(workOrderId)
193	                .orElseGet(() -> WorkOrderCost.builder()
194	                        .workOrderId(workOrderId)
195	                        .partsCost(BigDecimal.ZERO)
196	                        .laborCost(BigDecimal.ZERO)
197	                        .build());
198	
199	        if (cost.getLockedAt() != null) {
200	            throw new AppException("COST_LOCKED", "Work order cost is locked and cannot be modified", HttpStatus.CONFLICT);
201	        }
202	
203	        BigDecimal prevParts = cost.getPartsCost();
204	        BigDecimal prevLabor = cost.getLaborCost();
205	
206	        if (request.getPartsCost() != null) cost.setPartsCost(request.getPartsCost());
207	        if (request.getLaborCost() != null) cost.setLaborCost(request.getLaborCost());
208	        if (request.getNotes() != null) cost.setNotes(request.getNotes());
209	        workOrderCostRepository.save(cost);
210	
211	        addEventInternal(workOrderId, WorkOrderEventType.COST_UPDATED, "Cost updated", actorId);
212	
213	        auditService.record(actorId, "WORK_ORDER", workOrderId.toString(),
214	                "UPDATE_COST", "USER_ACTION",
215	                Map.of("partsCost", prevParts.toPlainString(), "laborCost", prevLabor.toPlainString()),
216	                Map.of("partsCost", cost.getPartsCost().toPlainString(), "laborCost", cost.getLaborCost().toPlainString()));
217	
218	        return toResponse(wo);
219	    }
