221	    @Transactional
222	    public WorkOrderResponse submitRating(UUID workOrderId, WorkOrderRatingRequest request, UUID userId) {
223	        permissionEnforcer.require("WORK_ORDER", "WRITE");
224	        WorkOrder wo = workOrderRepository.findById(workOrderId)
225	                .orElseThrow(() -> new AppException("WORK_ORDER_NOT_FOUND", "Work order not found", HttpStatus.NOT_FOUND));
226	        assertWorkOrderWriteAccess(wo, userId);
227	
228	        if (workOrderRatingRepository.findByWorkOrderId(workOrderId).isPresent()) {
229	            throw new AppException("ALREADY_RATED", "This work order has already been rated", HttpStatus.CONFLICT);
230	        }
231	
232	        WorkOrderRating rating = WorkOrderRating.builder()
233	                .workOrderId(workOrderId)
234	                .raterUserId(userId)
235	                .rating(request.getRating())
236	                .comment(request.getComment())
237	                .build();
238	        workOrderRatingRepository.save(rating);
239	
240	        if (wo.getStatus() == WorkOrderStatus.RESOLVED) {
241	            wo.setStatus(WorkOrderStatus.CLOSED);
242	            workOrderRepository.save(wo);
243	        }
244	
245	        auditService.record(userId, "WORK_ORDER", workOrderId.toString(),
246	                "SUBMIT_RATING", "USER_ACTION",
247	                null, Map.of("rating", String.valueOf(request.getRating())));
248	
249	        return toResponse(wo);
250	    }
