252	    public WorkOrderAnalyticsResponse getAnalytics(LocalDate from, LocalDate to,
253	                                                    UUID technicianId, String statusStr) {
254	        // RLS: callers without ADMIN:READ can only see their own work orders
255	        if (!SecurityUtils.hasPermission("ADMIN", "READ")) {
256	            technicianId = SecurityUtils.getCurrentUserId();
257	        }
258	        WorkOrderStatus status = null;
259	        if (statusStr != null && !statusStr.isBlank()) {
260	            try { status = WorkOrderStatus.valueOf(statusStr); } catch (Exception e) { /* ignore */ }
261	        }
262	        OffsetDateTime fromDt = from != null
263	                ? from.atStartOfDay().atOffset(ZoneOffset.UTC)
264	                : OffsetDateTime.now().minusYears(10);
265	        OffsetDateTime toDt = to != null
266	                ? to.plusDays(1).atStartOfDay().atOffset(ZoneOffset.UTC)
267	                : OffsetDateTime.now().plusDays(1);
268	
269	        List<WorkOrder> orders = workOrderRepository.findForAnalytics(technicianId, status, fromDt, toDt);
270	
271	        long submitted = orders.stream().filter(w -> w.getStatus() == WorkOrderStatus.SUBMITTED).count();
272	        long assigned = orders.stream().filter(w -> w.getStatus() == WorkOrderStatus.ASSIGNED).count();
273	        long inProgress = orders.stream().filter(w -> w.getStatus() == WorkOrderStatus.IN_PROGRESS).count();
274	        long resolved = orders.stream().filter(w -> w.getStatus() == WorkOrderStatus.RESOLVED).count();
275	        long closed = orders.stream().filter(w -> w.getStatus() == WorkOrderStatus.CLOSED).count();
276	
277	        double avgRating = orders.stream()
278	                .mapToInt(w -> workOrderRatingRepository.findByWorkOrderId(w.getId())
279	                        .map(WorkOrderRating::getRating).orElse(0))
280	                .filter(r -> r > 0)
281	                .average().orElse(0.0);
282	
283	        BigDecimal totalParts = orders.stream()
284	                .map(w -> workOrderCostRepository.findByWorkOrderId(w.getId())
285	                        .map(WorkOrderCost::getPartsCost).orElse(BigDecimal.ZERO))
286	                .reduce(BigDecimal.ZERO, BigDecimal::add);
287	
288	        BigDecimal totalLabor = orders.stream()
289	                .map(w -> workOrderCostRepository.findByWorkOrderId(w.getId())
290	                        .map(WorkOrderCost::getLaborCost).orElse(BigDecimal.ZERO))
291	                .reduce(BigDecimal.ZERO, BigDecimal::add);
292	
293	        return WorkOrderAnalyticsResponse.builder()
294	                .total(orders.size())
295	                .submitted(submitted)
296	                .assigned(assigned)
297	                .inProgress(inProgress)
298	                .resolved(resolved)
299	                .closed(closed)
300	                .avgRating(avgRating)
301	                .totalPartsCost(totalParts)
302	                .totalLaborCost(totalLabor)
303	                .build();
304	    }
