306	    public byte[] exportCsv() {
307	        permissionEnforcer.require("ADMIN", "READ");
308	        List<WorkOrder> all = workOrderRepository.findAll();
309	        try (StringWriter sw = new StringWriter(); CSVWriter writer = new CSVWriter(sw)) {
310	            writer.writeNext(new String[]{"ID", "Number", "Status", "Technician", "Created"});
311	            for (WorkOrder wo : all) {
312	                writer.writeNext(new String[]{
313	                        wo.getId().toString(),
314	                        wo.getWorkOrderNumber(),
315	                        wo.getStatus().name(),
316	                        wo.getTechnicianUserId() != null ? wo.getTechnicianUserId().toString() : "",
317	                        wo.getCreatedAt().toString()
318	                });
319	            }
320	            return sw.toString().getBytes(java.nio.charset.StandardCharsets.UTF_8);
321	        } catch (Exception e) {
322	            throw new AppException("EXPORT_FAILED", "Failed to export CSV", HttpStatus.INTERNAL_SERVER_ERROR, e);
323	        }
324	    }
