326	    // E) Include persisted attachments in every work-order response
327	    public WorkOrderResponse toResponse(WorkOrder wo) {
328	        List<AttachmentResponse> attachments = Collections.emptyList();
329	        if (wo.getId() != null) {
330	            attachments = attachmentRepository.findByOwnerTypeAndOwnerId("WORK_ORDER", wo.getId())
331	                    .stream()
332	                    .map(a -> AttachmentResponse.builder()
333	                            .id(a.getId())
334	                            .ownerType(a.getOwnerType())
335	                            .ownerId(a.getOwnerId())
336	                            .blobRef(a.getBlobRef())
337	                            .contentType(a.getContentType())
338	                            .createdAt(a.getCreatedAt())
339	                            .build())
340	                    .collect(Collectors.toList());
341	        }
342	        return WorkOrderResponse.builder()
343	                .id(wo.getId())
344	                .workOrderNumber(wo.getWorkOrderNumber())
345	                .orderId(wo.getOrderId())
346	                .technicianUserId(wo.getTechnicianUserId())
347	                .status(wo.getStatus())
348	                .description(wo.getDescription())
349	                .slaFirstResponseDueAt(wo.getSlaFirstResponseDueAt())
350	                .slaResolutionDueAt(wo.getSlaResolutionDueAt())
351	                .firstRespondedAt(wo.getFirstRespondedAt())
352	                .resolvedAt(wo.getResolvedAt())
353	                .createdAt(wo.getCreatedAt())
354	                .attachments(attachments)
355	                .build();
356	    }
