53	    private static final AtomicLong orderSeq = new AtomicLong(System.currentTimeMillis() % 100000);
54	
55	    // -----------------------------------------------------------------------
56	    // A) Object-level authorization helper (IDOR prevention)
57	    // Non-admin callers must own the order. forWrite=true requires ADMIN:WRITE
58	    // for the admin bypass; forWrite=false requires ADMIN:READ.
59	    // -----------------------------------------------------------------------
60	    private void assertOrderOwnership(Order order, boolean forWrite) {
61	        UUID callerId = SecurityUtils.getCurrentUserId();
62	        boolean isOwner = callerId.equals(order.getBuyerUserId());
63	        String adminOp = forWrite ? "WRITE" : "READ";
64	        if (!isOwner && !SecurityUtils.hasPermission("ADMIN", adminOp)) {
65	            throw new AppException("FORBIDDEN",
66	                    "You do not have access to this order", HttpStatus.FORBIDDEN);
67	        }
68	    }
69	
70	    @Transactional
71	    public OrderPlacementResult placeOrder(PlaceOrderRequest request, String idempotencyKey) {
72	        permissionEnforcer.require("ORDER", "WRITE");
73	        // C) Time-windowed idempotency — DB unique constraint was dropped in V6.
74	        //    Return replay=true (HTTP 200) if the same key was used within 10 min.
75	        if (idempotencyKey != null && !idempotencyKey.isBlank()) {
76	            String keyHash = hashIdempotencyKey(request.getBuyerId(), idempotencyKey);
77	            Optional<Order> existing = orderRepository.findTopByBuyerUserIdAndIdempotencyKeyHashOrderByCreatedAtDesc(
78	                    request.getBuyerId(), keyHash);
79	            if (existing.isPresent()) {
80	                Order existingOrder = existing.get();
81	                if (existingOrder.getCreatedAt().isAfter(OffsetDateTime.now().minusMinutes(10))) {
82	                    return new OrderPlacementResult(toResponse(existingOrder), true);
83	                }
84	            }
85	        }
86	
87	        // Compute subtotal
88	        BigDecimal subtotal = request.getItems().stream()
89	                .map(item -> item.getUnitPrice().multiply(BigDecimal.valueOf(item.getQuantity())))
90	                .reduce(BigDecimal.ZERO, BigDecimal::add);
91	
92	        BigDecimal shippingCost = computeShipping(request.getShippingCountry());
93	
94	        // Pricing
95	        PricingResult pricing = pricingEngine.computePricing(
96	                request.getBuyerId(), subtotal, shippingCost,
97	                request.getCouponCode(), request.getCampaignId());
98	
99	        // All-or-nothing inventory reservation (Q9):
100	        // Pass 1 — acquire pessimistic locks and verify ALL items are available before
101	        //           touching any reserved count. Use a LinkedHashMap to preserve order
102	        //           and deduplicate SKUs (aggregate quantities for duplicate SKU entries).
103	        Map<String, Integer> skuQuantities = new LinkedHashMap<>();
104	        for (var item : request.getItems()) {
105	            skuQuantities.merge(item.getSku(), item.getQuantity(), Integer::sum);
106	        }
107	
108	        Map<String, Inventory> lockedInventory = new LinkedHashMap<>();
109	        for (Map.Entry<String, Integer> entry : skuQuantities.entrySet()) {
110	            String sku = entry.getKey();
111	            int qty     = entry.getValue();
112	            Inventory inv = inventoryRepository.findBySkuWithLock(sku)
113	                    .orElseThrow(() -> new AppException("INVENTORY_NOT_FOUND",
114	                            "SKU not found: " + sku, HttpStatus.NOT_FOUND));
115	            int available = inv.getOnHand() - inv.getReserved();
116	            if (available < qty) {
117	                throw new AppException("INSUFFICIENT_INVENTORY",
118	                        "Insufficient inventory for SKU " + sku +
119	                        ": available=" + available + " requested=" + qty,
120	                        HttpStatus.UNPROCESSABLE_ENTITY);
121	            }
122	            lockedInventory.put(sku, inv);
123	        }
124	
125	        // Pass 2 — all checks passed; reserve every SKU atomically within this TX.
126	        OffsetDateTime reservedUntil = OffsetDateTime.now().plusMinutes(30);
127	        for (Map.Entry<String, Integer> entry : skuQuantities.entrySet()) {
128	            Inventory inv = lockedInventory.get(entry.getKey());
129	            inv.setReserved(inv.getReserved() + entry.getValue());
130	            inv.setReservedUntil(reservedUntil);
131	            inventoryRepository.save(inv);
132	        }
133	        auditService.record(request.getBuyerId(), "INVENTORY", null,
134	                "INVENTORY_RESERVE", "USER_ACTION",
135	                null, Map.of("skus", skuQuantities));
136	
137	        // Create order
138	        String orderNumber = "ORD-" + System.currentTimeMillis() + "-" + orderSeq.incrementAndGet();
139	        String idempotencyKeyHash = idempotencyKey != null ?
140	                hashIdempotencyKey(request.getBuyerId(), idempotencyKey) : null;
141	
142	        Order order = Order.builder()
143	                .orderNumber(orderNumber)
144	                .buyerUserId(request.getBuyerId())
145	                .status(OrderStatus.PLACED)
146	                .subtotal(subtotal)
147	                .discountsTotal(pricing.getDiscountsTotal())
148	                .shippingTotal(pricing.getShippingTotal())
149	                .totalPayable(pricing.getTotalPayable())
150	                .couponId(pricing.getAppliedCouponId())
151	                .campaignId(pricing.getAppliedCampaignId())
152	                .paymentMethod(request.getPaymentMethod())
153	                .shippingCountry(request.getShippingCountry())
154	                .shippingPostalCode(request.getShippingPostalCode())
155	                .idempotencyKeyHash(idempotencyKeyHash)
156	                .items(new ArrayList<>())
157	                .build();
158	
159	        order = orderRepository.save(order);
160	
161	        // Create items
162	        List<OrderItem> items = new ArrayList<>();
163	        for (var itemDto : request.getItems()) {
164	            OrderItem item = OrderItem.builder()
165	                    .orderId(order.getId())
166	                    .sku(itemDto.getSku())
167	                    .quantity(itemDto.getQuantity())
168	                    .unitPrice(itemDto.getUnitPrice())
169	                    .lineTotal(itemDto.getUnitPrice().multiply(BigDecimal.valueOf(itemDto.getQuantity())))
170	                    .build();
171	            items.add(orderItemRepository.save(item));
172	        }
173	        order.setItems(items);
174	
175	        auditService.record(request.getBuyerId(), "ORDER", order.getId().toString(),
