385	    @Transactional
386	    public void closeTimedOutOrders() {
387	        OffsetDateTime cutoff = OffsetDateTime.now().minusMinutes(30);
388	        List<Order> timedOut = orderRepository.findTimedOutOrders(cutoff);
389	
390	        for (Order order : timedOut) {
391	            log.info("Closing timed-out order: {}", order.getOrderNumber());
392	            // Release inventory
393	            List<OrderItem> items = orderItemRepository.findByOrderId(order.getId());
394	            for (OrderItem item : items) {
395	                inventoryRepository.findBySkuWithLock(item.getSku()).ifPresent(inv -> {
396	                    inv.setReserved(Math.max(0, inv.getReserved() - item.getQuantity()));
397	                    inventoryRepository.save(inv);
398	                });
399	            }
400	            order.setStatus(OrderStatus.CLOSED);
401	            order.setClosedAt(OffsetDateTime.now());
402	            orderRepository.save(order);
403	            auditService.record(null, "INVENTORY", order.getOrderNumber(),
404	                    "INVENTORY_RELEASE", "SYSTEM_TIMEOUT",
405	                    null, Map.of("orderId", order.getId().toString()));
406	        }
407	    }
