409	    private BigDecimal computeShipping(String country) {
410	        // Simple flat rate
411	        if ("US".equalsIgnoreCase(country)) return BigDecimal.valueOf(10.00);
412	        if (country == null) return BigDecimal.valueOf(15.00);
413	        return BigDecimal.valueOf(25.00);
414	    }
