455	    private OrderItemResponse toItemResponse(OrderItem item) {
456	        return OrderItemResponse.builder()
457	                .id(item.getId())
458	                .sku(item.getSku())
459	                .quantity(item.getQuantity())
460	                .unitPrice(item.getUnitPrice())
461	                .lineTotal(item.getLineTotal())
462	                .build();
463	    }
